module top_module(cout, resetn, clk, d) ;input [27:0] d;
	input resetn, clk;
	output cout; 

	reg [27:0] cnt;

	always @ (posedge clk)
	begin 
		if (resetn == 1'b0)
		begin
			cnt <= d;
		end

		else 
		begin 
			if (cnt == 0)
			begin
				cnt <= d;
			end
			else
			begin
				cnt <= cnt - 1;
			end
		end
	end

	assign cout = (cnt == 0) ? 1 : 0;endmodule
